let d = traces | where message == 'UsageMetrics' | where tostring(customDimensions.bot_env) == '{Environment}' | where tostring(customDimensions.status) != 'failure';
let pages = todouble(coalesce(toscalar(d | summarize sum(toint(customDimensions.ocr_pages))), 0));
let chars = todouble(coalesce(toscalar(d | summarize sum(toint(customDimensions.tts_chars))), 0));
union
(print Metric = 'OCR cost ($)', Value = round(pages * 0.0015, 2)),
(print Metric = 'TTS cost ($)', Value = round(chars * 0.000016, 2)),
(print Metric = 'Total est. cost ($)', Value = round(pages * 0.0015 + chars * 0.000016, 2))

let d = traces | where message == 'UsageMetrics' | where tostring(customDimensions.bot_env) == '{Environment}';
let total = todouble(coalesce(toscalar(d | summarize count()), 0));
let fails = todouble(coalesce(toscalar(d | summarize countif(tostring(customDimensions.status) == 'failure')), 0));
union
(print Metric = 'Total requests', Value = total),
(print Metric = 'Failures', Value = fails),
(print Metric = 'Success rate %', Value = iff(total == 0, 100.0, round(100.0 * (total - fails) / total, 1)))

let g = traces
| where message == 'GrowthMetrics'
| where tostring(customDimensions.bot_env) == '{Environment}'
| extend e = tostring(customDimensions.event_type);
let views = todouble(coalesce(toscalar(g | summarize countif(e == 'support_view')), 0));
let pack_clicks = todouble(coalesce(toscalar(g | summarize countif(e == 'support_pack_click')), 0));
let created = todouble(coalesce(toscalar(g | summarize countif(e == 'support_request_created')), 0));
let granted = todouble(coalesce(toscalar(g | summarize countif(e == 'support_bonus_granted')), 0));
let rejected = todouble(coalesce(toscalar(g | summarize countif(e == 'support_request_rejected')), 0));
union
(print Metric = 'Support views', Value = views),
(print Metric = 'Pack clicks', Value = pack_clicks),
(print Metric = 'Requests created', Value = created),
(print Metric = 'Bonuses granted', Value = granted),
(print Metric = 'Requests rejected', Value = rejected),
(print Metric = 'View -> click %', Value = iff(views == 0, 0.0, round(100.0 * pack_clicks / views, 1))),
(print Metric = 'Created -> granted %', Value = iff(created == 0, 0.0, round(100.0 * granted / created, 1)))
